import{_ as i,c as e,a as l,o as n}from"./app-CEcM0piI.js";const s={};function h(r,a){return n(),e("div",null,a[0]||(a[0]=[l('<p>你好，我叫xxx，xxxx，读的是xxx专业。爱好广泛的人。我很喜欢前端开发这个工作，愿意迎接挑战并在克服困难、解决问题的过程中不断地提升自己。</p><h1 id="自己的优缺点" tabindex="-1"><a class="header-anchor" href="#自己的优缺点"><span>自己的优缺点</span></a></h1><h2 id="缺点" tabindex="-1"><a class="header-anchor" href="#缺点"><span>缺点</span></a></h2><ul><li>对很多东西都很感兴趣：就像我简历上写的那样像前端后端，c++，python，游戏开发等都有涉猎。但后来感觉在一个领域深耕才能有更大成就，现在也在改正这个缺点</li><li>如果有很多事情我习惯先做完一件事再做其他事除非是接近安全期限：我当时做的那个插件大版本更新的时候刚好赶上期中考试，虽然我之前有提前学习课程内容，但当时最理智的做法应该是先准备期中考试，考完后再继续做插件。但是我当时的选择是拼命赶插件，后来在其中考前四天做好了，留了四天的时间复习，稍微有点少，我通常期望的复习时间一般是一周以上</li></ul><h2 id="优点" tabindex="-1"><a class="header-anchor" href="#优点"><span>优点</span></a></h2><ul><li>细心：我在开发那个插件之前看了其他很多插件（当时没打算做插件的），当时我就选了一个仿one dark的插件，one dark是一个用户非常多的几个插件之一，当时我觉得那个仿的它背景颜色比one dark更浅些，这样切换其他页面，因为工作的时候其他页面通常都是亮色的，而我代码编辑器都是暗色的，在切换的时候眼睛会有些不舒服。用了一段时间后我感觉有些地方的颜色我不喜欢，我想改成自己的颜色，还有就是文件目录树的线条颜色也不好，不太容易分辨文件目录的层次结构，还有就是代码缩进的线条颜色和背景同色，也影响看缩进的层级，于是就想着自己做一个插件，然后上网上去搜索教程，就做了出来。发现有些地方主题适配的不好，我也试了其他插件感觉都不好，然后我又用了官方的主题当时突然明白官方的主题适配的才是最好的。我就又找到官方的主题文件所在目录，用官方的主题改了。后来我又用了一段时间，觉得既然其他应用的亮色与代码编辑器的暗色切换眼睛不适应可以直接用亮色主题，但是用了很多亮色主题发现它们的代码高亮对比度很低，也就自己做了个亮色的主题。还有在用文件图标的时候感觉文件图标的风格很割裂，就比如原本用的一个图标主题它风格是扁平化的，但是有些文件却是拟物风，而且文件图标不能表现出文件的特点，就比如yml文件，主要特定应该是缩进的写法，但是它有些图标都是一个普通文档的图标加上一个不同颜色的横幅写上文件后缀名，我觉得这个图标不能帮助用户快速分辨文件的类型，所以我就也做了图标，我的图标设计语言是：扁平化，精简，尽量贴合官方的图标，当然如果官方的图标特别复杂也会对他进行精简，因为我觉得扁平化更加适合电脑屏幕的显示风格。就比如babel图标它官方的图标是bable，但我的是一个官方同款字体和颜色的大b的图标，原本主题图标比如js，ts等都是一个方形的背景加上镂空的js，ts字样，我就改成了直接一个js，ts字样，比如c和c++的源文件和头文件原本的图标都是同一个颜色的，我把它们源文件和头文件分为了不同的颜色，同时hpp文件宽度较长我使用了更加紧凑的图标样式</li><li>坚持：</li><li>好奇：</li><li>洞察力：</li></ul><h1 id="一个让自己很遗憾的事情" tabindex="-1"><a class="header-anchor" href="#一个让自己很遗憾的事情"><span>一个让自己很遗憾的事情</span></a></h1><ul><li>自己的职业规划没有很好：我在决定深耕前端之前学了很多其他知识，像c/c++，qt，java，游戏开发，python，docker等，这些都是与前端开发交集不那么多甚至没交集的知识。其实我在大二学的qt，当时我就觉得相比于那些后台的东西（像单片机，linux api这些）我更喜欢做一个让人可以操作的页面，但是当时还想着做c++岗位，直到大三我学完前端并且在学校阻止的模拟面试的时候才知道自己喜欢的是做前端。</li><li>如果能够重新选择，我应该大二就开始学前端，像java后端的技术也不打算学，打算学大前端</li></ul><h1 id="最近在看什么书" tabindex="-1"><a class="header-anchor" href="#最近在看什么书"><span>最近在看什么书</span></a></h1><ul><li>现代c++语言核心特性解析：各种现代语法特性讲解十分清晰，比直接看官方文档更加符合中国人的语言习惯，缺点是只给出了讲解和实例代码，却很少给出应用的场景，但我觉得这个是我自己的问题，因为当时看这本书的时候我还没做过项目，当时看完一部分内容，我虽然懂了这个特性怎么用，但是不懂为什么要有这个特性。后来做了项目就懂了，像内联命名空间，右值引用，initisliter_list，默认和删除函数，静态断言等。总体来说是一本很好的书。可惜我没在正确的时间去读</li><li>c和指针：写的通俗易懂还有趣味性，感觉比上一本更加通俗易懂，而且给出的知识点也很碎很适合碎片化时间去读，这些只是免费章节部分的感觉，后面的收费部分我还没看</li><li>k&amp;r：是外国人写的，我虽然看完了但感觉很晦涩</li></ul><h1 id="兴趣爱好" tabindex="-1"><a class="header-anchor" href="#兴趣爱好"><span>兴趣爱好</span></a></h1><ul><li>游戏开发</li><li>羽毛球</li><li>排球</li></ul><h1 id="你还有什么问题要问吗" tabindex="-1"><a class="header-anchor" href="#你还有什么问题要问吗"><span>你还有什么问题要问吗？</span></a></h1><p><strong>技术面</strong></p><ul><li>面试流程通常持续多久</li><li>团队的核心业务以及技术栈</li></ul><p><strong>hr面</strong></p><ul><li>入职前要培训吗，培训时间是多久</li><li>人才培养体系是什么样的</li><li>转正率</li><li>薪酬结构</li><li>绩效考核</li></ul><h1 id="在五年的时间内-你的职业规划" tabindex="-1"><a class="header-anchor" href="#在五年的时间内-你的职业规划"><span>在五年的时间内，你的职业规划？</span></a></h1><p>我是计算机专业出身，我的专业技能也相对贴合团队，所以我是准备在这个行业长期发展下去的。我想从普通的开发岗位做起，慢慢积累经验，大概两三年左右，希望能够更进一步，做到更高的职位。</p><h2 id="为什么不选择考研考公" tabindex="-1"><a class="header-anchor" href="#为什么不选择考研考公"><span>为什么不选择考研考公</span></a></h2><p>因为我觉得中国现在毕业生人口众多，且即将进入老龄化社会，尤其是近几年毕业生人数一届比一届多，我如果考研的话要再晚些时间找工作，每晚一年就要多和几百万人竞争岗位，后续竞争压力大。 其次因为年轻人大都不愿意生孩子，未来中国人口很可能急速下滑，这些都和日本和韩国类似，未来政府的税收也支撑不了现在那么多的官僚群体，公务员未来应该是要裁员或者降低福利。借鉴日本等国的情况，直接就业是我觉得对我自己而言是一个比较好的选择 最后就是即使是考研研究生毕业依旧要就业</p><h1 id="请说出你选择这份工作的动机" tabindex="-1"><a class="header-anchor" href="#请说出你选择这份工作的动机"><span>请说出你选择这份工作的动机</span></a></h1><ul><li>首先专业对口，而我自己对这个行业也有浓厚的兴趣，经过慎重考虑并且想要在这个行业中长期发展才选择贵公司的，也希望可以在这里积累到丰富的工作经验。</li><li>其次因为贵司规模较大，部门职责，绩效考察、成员结构等都划分的比较明显且合理，风险也比较低。同时规模较大的公司业务团队，遇到问题的解决方案等也比较成熟，也会很少踩坑。在这样的公司工作可以学到很多东西，也能更多的累积经验</li></ul><h1 id="项目背景-遇到的难题" tabindex="-1"><a class="header-anchor" href="#项目背景-遇到的难题"><span>项目背景，遇到的难题</span></a></h1><p>是我现在手上的一个项目，这个项目有一个后台管理平台，将许多分类以及其中的子分类和节点都要以树形呈现出来，同时还要允许用户可以拖拽移动某个节点或者某个分类以及其下面的子分类和节点到另一个分类中，且分类的树的层级有一定要求，不能过长。我当时使用了elementplus中的树形组件将数据呈现出来了，但拖拽的情况比较复杂，我当时想到一种方法到实际写算法的时候又发现许多不妥之处，再重新想其他的解决方法也都有漏洞。我就想到这个拖拽的需求也是一个比较常见的功能，可以去网上看看别人有没有现有的解决方案，我就找到了一个，然后借用了他的方案，但也有一些简单的算法，我结合ai也就实现出来了</p><h1 id="成就感的事" tabindex="-1"><a class="header-anchor" href="#成就感的事"><span>成就感的事</span></a></h1><p>就是我开发的那个主题插件，这个插件是根据我自己的喜好开发的，各方面也都符合我自己的审美，而且在工作的过程中的也一直在使用，也对我的工作效率有一定提高。而且这个主题插件我也推荐给我的朋友门用了，它们有很多人也都喜欢。除此之外还有其他程序员同行们也有使用，现在下载量已有200+。这个是我独自开发的第一个开源项目有一种特殊的成就感，尤其是有同行在使用时遇到bug向我反馈</p><h1 id="自己的学习方式" tabindex="-1"><a class="header-anchor" href="#自己的学习方式"><span>自己的学习方式</span></a></h1><p>我一般是首先在网上找一些视频，如果视频教程可以的话就会选择看视频学习。如果这类教程没有视频或者视频的质量不好或者不全面时我会选择找一些大家推荐的书籍去学习，如果书籍也很少或者阅读体验不好时我会选择看官方文档。</p><h1 id="看重工作的什么方面" tabindex="-1"><a class="header-anchor" href="#看重工作的什么方面"><span>看重工作的什么方面</span></a></h1><ul><li>团队的氛围如何：我觉得人是容易受环境影响的，如果是在一个氛围差的环境中工作更容易被消耗精力，如果是在氛围好的环境中工作不仅反而可能增加人的积极性</li><li>与个人的匹配度：我有打算在这个领域中深耕，如果在这个匹配的岗位中工作我将会少很多新的要学习的东西，可以将这些时间和精力放在工作上以及提升自我上</li></ul><h1 id="多个意向怎么选择" tabindex="-1"><a class="header-anchor" href="#多个意向怎么选择"><span>多个意向怎么选择</span></a></h1><ul><li>首先是自己优势比较突出的那个：因为这个方面我的优势比较突出，也就会容易通过面试，获得offer</li><li>其次如果薪资差距不过大的话我会更倾向选择自己更爱好的那个：如果在自己爱好上工作的话会更加有积极性。而且也会更愿意在工作之外来提升自己这部分能力</li></ul><h1 id="有压力大的时候吗" tabindex="-1"><a class="header-anchor" href="#有压力大的时候吗"><span>有压力大的时候吗</span></a></h1><p>有，在刚开始求职的时候，投简历石沉大海，与我自己的心理有一些落差，而且那段时间我还有一个参加比赛的项目要做，就要一边做项目一边投简历，投出去的简历也有一部分约定面试的，此时我还要准备面试等。当时压力就挺大 我一般有三种方法解决：</p><ol><li>找朋友倾诉</li><li>和朋友一起去运动</li><li>闭目养神：这种一般是在白天且身心俱疲的情况下，因为晚上的话我可以直接睡觉，但白天睡觉会影响到我晚上的睡眠质量，</li></ol>',36)]))}const p=i(s,[["render",h]]),d=JSON.parse('{"path":"/front/interview/1/","title":"1. 通用","lang":"zh-CN","frontmatter":{"title":"1. 通用","createTime":"2025/06/18 09:16:08","permalink":"/front/interview/1/"},"readingTime":{"minutes":10.5,"words":3150},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/面经/1. 通用.md","headers":[]}');export{p as comp,d as data};
